from typing import Iterable

def cube_Sum(n: int) -> int:
    match n:
        case 0:
            odd_cubes: Iterable[int] = (0,)
        case _:
            if n > 0:
                if n == 1:
                    odd_cubes: Iterable[int] = (1,)
                else:
                    result: int = n ** 2 * (2 * n ** 2 - 1)
                    odd_cubes: Iterable[int] = (result,)
            else:
                raise ValueError("n must be a non-negative integer")
    return sum(odd_cubes)

