import re

def check_variable_naming_with_digit(tree, convention, **kwargs):
    """
    Checks all variable names against the {convention} and ensures they contain at least one digit.
    """
    assert convention in ["snake_case", "camelCase", "PascalCase"], \
        f"Invalid convention: {convention}. Must be one of ['snake_case', 'camelCase', 'PascalCase']."

    vars_to_check = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name):
                    vars_to_check.add(target.id)
        elif isinstance(node, ast.AnnAssign):
            if isinstance(node.target, ast.Name):
                vars_to_check.add(node.target.id)

    if not vars_to_check:
        return True 

    patterns = {
        "snake_case": r"^[a-z_][a-z0-9_]*$",
        "camelCase": r"^[a-z][a-zA-Z0-9]*$",
        "PascalCase": r"^[A-Z][a-zA-Z0-9]*$"
    }

    pattern = patterns.get(convention)
    if not pattern:
        return False 

    for var in vars_to_check:
        if not re.match(pattern, var):
            return False
        # New constraint: variable must contain at least one digit
        if not any(char.isdigit() for char in var):
            return False
    return True

