    arr_z_val: int = 0
    for arr_n_val in filter(lambda x: x == 0, nums):
        arr_z_val += 1
    arr_t_val: int = len(nums)
    if arr_t_val == 0:
        return 0.0
    else:
        ratio_val: float = arr_z_val / arr_t_val
        return int(ratio_val * 100 + 0.5) / 100

