def validate(n):
    s = str(n)
    # List comprehension to count each digit's frequency using filter (required) instead of inner list comprehension
    frequencies = [len(list(filter(lambda c: c == str(digit), s))) for digit in range(10)]
    # Check all frequency conditions using all()
    return all(freq <= digit for freq, digit in zip(frequencies, range(10)))

