def remove_dirty_chars(string: str, second_string: str) -> str:
    def is_allowed(char: str) -> bool:
        return char not in set(second_string)
    def recursive_helper(s: str) -> str:
        if len(s) == 0:
            return ""
        return ''.join(filter(is_allowed, s[0])) + recursive_helper(s[1:])
    return recursive_helper(string)

