import re
def pass_validity(p):
    validation_checks = {
        "length": lambda s: 6 <= len(s) <= 12,
        "lowercase": lambda s: re.search("[a-z]", s),
        "uppercase": lambda s: re.search("[A-Z]", s),
        "digit": lambda s: re.search("[0-9]", s),
        "special_char": lambda s: re.search("[$#@]", s),
        "no_whitespace": lambda s: not re.search("\s", s)
    }

    def recursive_check(checks):
        if not checks:
            return True
        current_check = checks[0]
        if not current_check(p):
            return False
        return recursive_check(checks[1:])

    return recursive_check(list(validation_checks.values()))

