def findKOr(nums, k):
    k_or_bit_counts = {}
    if not nums:
        return 0
    k_or_max_bit = max(nums).bit_length()
    for k_or_pos in range(k_or_max_bit):
        k_or_count = sum(map(lambda num: (num >> k_or_pos) & 1, nums))
        k_or_bit_counts[k_or_pos] = k_or_count
    k_or_ans = 0
    for k_or_pos, k_or_cnt in k_or_bit_counts.items():
        if k_or_cnt >= k:
            k_or_ans |= 1 << k_or_pos
    return k_or_ans

