class NumberConverter:
    @staticmethod
    def decimal_to_binary(decimal_num_val: int) -> str:
        def _recursive_convert(n_val: int) -> str:
            match n_val:
                case 0:
                    return ""
                case _:
                    return _recursive_convert(n_val // 2) + str(n_val % 2)
        if decimal_num_val == 0:
            return "0"
        binary_num_val: str = _recursive_convert(decimal_num_val)
        return binary_num_val

    @staticmethod
    def binary_to_decimal(binary_num_val: str) -> int:
        decimal_num_val: int = 0
        for char_val in binary_num_val:
            decimal_num_val = decimal_num_val * 2 + (1 if char_val == '1' else 0)
        return decimal_num_val

    @staticmethod
    def decimal_to_octal(decimal_num_val: int) -> str:
        def _recursive_convert(n_val: int) -> str:
            match n_val:
                case 0:
                    return ""
                case _:
                    return _recursive_convert(n_val // 8) + str(n_val % 8)
        if decimal_num_val == 0:
            return "0"
        octal_num_val: str = _recursive_convert(decimal_num_val)
        return octal_num_val

    @staticmethod
    def octal_to_decimal(octal_num_val: str) -> int:
        decimal_num_val: int = 0
        for char_val in octal_num_val:
            decimal_num_val = decimal_num_val * 8 + (ord(char_val) - ord('0'))
        return decimal_num_val

    @staticmethod
    def decimal_to_hex(decimal_num_val: int) -> str:
        hex_digits_val: str = "0123456789abcdef"
        def _recursive_convert(n_val: int) -> str:
            match n_val:
                case 0:
                    return ""
                case _:
                    return _recursive_convert(n_val // 16) + hex_digits_val[n_val % 16]
        if decimal_num_val == 0:
            return "0"
        hex_num_val: str = _recursive_convert(decimal_num_val)
        return hex_num_val

    @staticmethod
    def hex_to_decimal(hex_num_val: str) -> int:
        decimal_num_val: int = 0
        hex_digits_val: str = "0123456789abcdef"
        for char_val in hex_num_val:
            decimal_num_val = decimal_num_val * 16 + hex_digits_val.index(char_val.lower())
        return decimal_num_val

