class Node: 
    def __init__(self, data: int) -> None: 
        self.data: int = data 
        self.left: Optional[Node] = None
        self.right: Optional[Node] = None

class TreeBalancer:
    @staticmethod
    def is_balanced(ROOT: Optional[Node]) -> bool:
        if ROOT is None:
            return True
        STACK: list[Tuple[Optional[Node], bool]] = [(ROOT, False)]
        HEIGHT_MAP: Dict[Node, int] = {}
        BALANCED: bool = True
        while STACK and BALANCED:  # Exactly 1 while loop
            NODE, VISITED = STACK.pop()
            if VISITED:
                LEFT_HEIGHT: int = HEIGHT_MAP.get(NODE.left, 0) if NODE.left is not None else 0
                RIGHT_HEIGHT: int = HEIGHT_MAP.get(NODE.right, 0) if NODE.right is not None else 0
                if abs(LEFT_HEIGHT - RIGHT_HEIGHT) > 1:
                    BALANCED = False
                HEIGHT_MAP[NODE] = 1 + max(LEFT_HEIGHT, RIGHT_HEIGHT)
            else:
                STACK.append((NODE, True))
                if NODE.right:
                    STACK.append((NODE.right, False))
                if NODE.left:
                    STACK.append((NODE.left, False))
        return BALANCED

def is_tree_balanced(ROOT: Optional[Node]) -> bool:
    return TreeBalancer.is_balanced(ROOT)

def check_balanced(ROOT: Optional[Node]) -> bool:
    return TreeBalancer.is_balanced(ROOT)

