class AbundantChecker:
    @staticmethod
    def get_divisors(n, i=1):
        divisors = set()
        if i > int(n**0.5):
            return divisors
        if n % i == 0:
            divisors.add(i)
            if i != n // i:
                divisors.add(n // i)
        return divisors.union(AbundantChecker.get_divisors(n, i + 1))

def check_abundant(n):
    all_divisors = AbundantChecker.get_divisors(n)
    proper_divisors_sum = 0
    proper_divisors_sum = sum([d for d in all_divisors if d != n])
    return proper_divisors_sum > n

