def solution(a: int, b: int, n: int) -> tuple[str, int, str, int] | str:
    # Calculate maximum possible x value (n divided by a, integer division)
    max_x: int = n // a
    # Create a dict mapping x values to their corresponding remainder (n - a*x)
    x_remainder_map: dict[int, int] = {i: n - i * a for i in range(max_x + 1)}
    for x, remainder in x_remainder_map.items():
        if remainder % b == 0:
            y: int = remainder // b
            return ("x = ", x, ", y = ", y)
    return "No solution"

