def strongPasswordCheckerII(password):
    if len(password) < 8:
        return False
    mask = 0
    for i, c in enumerate(password):
        if i and c == password[i - 1]:
            return False
        if c.islower():
            mask |= 1
        elif c.isupper():
            mask |= 2
        elif c.isdigit():
            mask |= 4
        else:
            mask |= 8
    return mask == 15

