memo = []

def zigzag(n, k):
    # Initialize memo as a 2D list using exactly one list comprehension
    memo = [[0] * (current_n + 1) for current_n in range(n + 1)]
    # Fill the memo table using nested for loops
    for current_n in range(n + 1):
        for current_k in range(current_n + 1):
            if current_n == 0 and current_k == 0:
                memo[current_n][current_k] = 1
            elif current_k == 0:
                memo[current_n][current_k] = 0
            else:
                val1 = memo[current_n][current_k - 1] if current_k - 1 >= 0 else 0
                val2 = memo[current_n - 1][current_n - current_k] if (current_n - 1 >= 0 and current_n - current_k >= 0) else 0
                memo[current_n][current_k] = val1 + val2
    return memo[n][k] if (n >= 0 and k >= 0 and k <= n) else 0

