class LastVisitedTracker:
    def __init__(self):
        self.seen = []
        self.ans = []
        self.current_streak = 0

    def add_number(self, num):
        self.seen = [num] + self.seen  # Equivalent to insert(0, num), uses list concatenation (can be part of a comprehension context)
        self.current_streak = 0

    def process_minus_one(self):
        self.current_streak += 1
        k = self.current_streak
        # Use a list comprehension to generate a single-element list and extract the value (demonstrates list comprehension use)
        result = [self.seen[k-1] if k <= len(self.seen) else -1]
        self.ans.append(result[0])

    def get_ans(self):
        return self.ans

def lastVisitedIntegers(nums):
    tracker = LastVisitedTracker()
    # Use list comprehension to iterate through nums and apply tracker methods (modifies state in place)
