def zigzag(n, k, memo=None):
    # Initialize memoization dictionary if not provided
    if memo is None:
        memo = {}
    key = (n, k)
    value = memo.get(key)
    if value is not None:
        return value
    # Base cases: both n and k are 0, or k is 0
    if n == 0 and k == 0:
        value = 1
    elif k == 0:
        value = 0
    # Recursive case: sum of two subproblems
    else:
        value = zigzag(n, k - 1, memo) + zigzag(n - 1, n - k, memo)
    memo[key] = value
    return value

