class SquareCounter:
    @staticmethod
    def calculate_squares(length: int, width: int) -> int:
        # Sort dimensions to get min (rectLengthVar) and max (rectWidthVar) for tile size iteration
        rectLengthVar: int = sorted([length, width])[0]
        rectWidthVar: int = sorted([length, width])[1]
        rectTotalTilesVar: int = 0
        # Iterate over each possible square tile size from 1 to the smaller dimension
        for rectTileSizeVar in range(1, rectLengthVar + 1):
            # Calculate number of tiles of current size: (available rows) * (available columns)
            rectTotalTilesVar += (rectLengthVar - rectTileSizeVar + 1) * (rectWidthVar - rectTileSizeVar + 1)
        return rectTotalTilesVar

def count_Squares(length: int, width: int) -> int:
    return SquareCounter.calculate_squares(length, width)

