def left_insertion(a_val, x_val):
    # Binary search to find left insertion point in sorted list
    def binary_search(low_val, high_val):
        mid_val = (low_val + high_val) // 2
        # If low >= high, return low as insertion point
        if low_val >= high_val:
            return low_val
        # Recurse on right half if mid element < x, else left half
        return binary_search(mid_val + 1, high_val) if a_val[mid_val] < x_val else binary_search(low_val, mid_val)
    return binary_search(0, len(a_val))

