from typing import Tuple

def add_nested_tuples(test_tup1: Tuple[Tuple[int, ...], ...], test_tup2: Tuple[Tuple[int, ...], ...]) -> Tuple[Tuple[int, ...], ...]:
    # Initialize result tuple to store outer nested structure
    outer_result: Tuple[Tuple[int, ...], ...] = ()
    outer_zip_iter = iter(zip(test_tup1, test_tup2))

    while True:
        try:
            inner_tup1, inner_tup2 = next(outer_zip_iter)
        except StopIteration:
            break
        inner_result: Tuple[int, ...] = ()

        if len(inner_tup1) == len(inner_tup2):
            # Iterate over corresponding elements of inner tuples
            inner_zip_iter = iter(zip(inner_tup1, inner_tup2))
            while True:
                try:
                    elem1, elem2 = next(inner_zip_iter)
                except StopIteration:
                    break
                inner_result += (elem1 + elem2,)
        else:
            # Raise error if inner tuples have mismatched lengths
            raise ValueError("Inner tuples must have the same length")

        outer_result += (inner_result,)
    return outer_result

