import copy
from typing import List

class ArrayReverser:
    @staticmethod
    def reverse_upto_k(arr: List, k_val: int) -> List:
        # Create a copy of input to avoid modifying original
        arrVar: List = copy.copy(arr)
        # Initialize left and right pointers for first k elements
        leftVar: int = 0
        rightVar: int = k_val - 1
        # Swap elements until pointers meet in first k elements
        while leftVar < rightVar:
            arrVar[leftVar], arrVar[rightVar] = arrVar[rightVar], arrVar[leftVar]
            leftVar += 1
            rightVar -= 1
        return arrVar

def reverse_Array_Upto_K(input: List, k: int) -> List:
    return ArrayReverser.reverse_upto_k(input, k)

