class MatrixAnalyzer:
    def __init__(self, mat: list[list[int]]) -> None:
        self.mat: list[list[int]] = mat
        self.rows: list[int] = [sum(row) for row in mat]  # Use sum for row sums
        self.cols: list[int] = [0] * len(mat[0]) if mat and mat[0] else []
        self._compute_cols()

    def _compute_cols(self) -> None:
        """Use sum and enumerate to compute column sums."""
        for j, col in enumerate(zip(*self.mat)):
            self.cols[j] = sum(col)  # Use sum for column sums

    def count_special(self) -> int:
        """Recursively count special positions using enumerate."""
        def count_recursive(i: int) -> int:
            if i >= len(self.mat):
                return 0
            row = self.mat[i]
            row_sum = self.rows[i]
            # Use enumerate to iterate over columns
            col_count: int = 0
            for j, val in enumerate(row):
                if val == 1 and row_sum == 1 and self.cols[j] == 1:
                    col_count += 1
            return col_count + count_recursive(i + 1)  # Recursive over rows
        return count_recursive(0)

def numSpecial(mat: list[list[int]]) -> int:
    analyzer: MatrixAnalyzer = MatrixAnalyzer(mat)
    return analyzer.count_special()

