def multiple_to_single(L):
    if not L:
        return 0
    # Handle sign
    sign = -1 if L[0] < 0 else 1
    total = 0
    for num in L:
        abs_num = abs(num)
        # Calculate number of digits in abs_num
        digit_count = 0
        temp = abs_num
        if temp == 0:
            digit_count = 1
        else:
            while temp > 0:
                digit_count += 1
                temp = temp // 10
        # Update total
        total = total * (10 ** digit_count) + abs_num
    return total * sign

