def duplicateZeros(arr):
    """
    Do not return anything, modify arr in-place instead.
    """
    n = len(arr)
    i, k = -1, 0
    while k < n:
        i += 1
        k += 1 if arr[i] else 2
    j = n - 1
    if k == n + 1:
        arr[j] = 0
        i, j = i - 1, j - 1
    while ~j:
        if arr[i] == 0:
            arr[j] = arr[j - 1] = arr[i]
            j -= 1
        else:
            arr[j] = arr[i]
        i, j = i - 1, j - 1

