import bisect

class MissingNumberFinder:
    @staticmethod
    def find_kth_positive(arr, k):
        if arr[0] > k:
            return k
        idx_var = bisect.bisect_left(arr, k + len(arr))
        missing_var = arr[idx_var - 1] - idx_var if idx_var > 0 else 0
        if missing_var < k:
            return k + idx_var
        left_var, right_var = 0, idx_var
        while left_var < right_var:
            mid_var = (left_var + right_var) >> 1
            if arr[mid_var] - mid_var - 1 >= k:
                right_var = mid_var
            else:
                left_var = mid_var + 1
        return arr[left_var - 1] + k - (arr[left_var - 1] - (left_var - 1) - 1)

def findKthPositive(arr, k):
    return MissingNumberFinder.find_kth_positive(arr, k)

