from typing import List
import math
from functools import reduce

def sm_gcd(sm_a: int, sm_b: int) -> int:
    # 递归计算最大公约数（欧几里得算法）
    if sm_b == 0:
        return sm_a
    return sm_gcd(sm_b, sm_a % sm_b)

def smallest_multiple(sm_n: int) -> int:
    # 递归终止条件：当sm_n为1时，最小公倍数是1
    if sm_n == 1:
        return 1
    # 使用reduce计算当前sm_n与前sm_n-1个数的最小公倍数，保持递归结构
    return reduce(lambda sm_x, sm_y: sm_x * sm_y // sm_gcd(sm_x, sm_y), [sm_n, smallest_multiple(sm_n - 1)])

