from typing import Callable

class CubeSumCalculator:
    @staticmethod
    def calculate(n: int) -> int:
        def cube_odd(i: int) -> int:
            return (2 * i + 1) ** 3
        if n <= 0:
            return 0
        else:
            cube_map: map[int, int] = map(cube_odd, range(n))
            return sum(cube_map)

