class CountHandler:
    def __init__(self, s):
        self.s = s
        self.counts = {'letters': 0, 'digits': 0}

    def count(self):
        index = 0
        while index < len(self.s):  # Exactly 1 while loop as required
            c = self.s[index]
            ord_c = ord(c)
            if 48 <= ord_c <= 57:  # Check if it's a digit (ASCII 0-9)
                self.counts['digits'] += 1
            elif 65 <= ord_c <= 90 or 97 <= ord_c <= 122:  # Check if it's a letter (ASCII A-Z or a-z)
                self.counts['letters'] += 1
            index += 1
        return (self.counts['letters'], self.counts['digits'])

def dig_let(s):
    handler = CountHandler(s)
    return handler.count()

