def binomial_Coeff(n, k):
    if k > n or k < 0:
        return 0
    if k == 0 or k == n:
        return 1
    # Use list comprehension to create DP table
    dp = [[0] * (k + 1) for _ in range(n + 1)]
    for i in range(n + 1):
        for j in range(min(i, k) + 1):
            if j == 0 or j == i:
                dp[i][j] = 1
            else:
                dp[i][j] = dp[i-1][j-1] + dp[i-1][j]
    return dp[n][k]

