    @staticmethod
    def get_unique_sorted(TEST_TUP):
        # Get unique elements using set
        UNIQUE_SET = set(TEST_TUP)
        # Convert set to list for manual sorting
        UNIQUE_LIST = list(UNIQUE_SET)
        # Define lambda function for comparison (exactly 1 as required)
        COMPARE = lambda a, b: a > b
        # Manual bubble sort using lambda for comparison
        N = len(UNIQUE_LIST)
        for I in range(N):
