def octal_To_Decimal(N: int) -> int:
    Digits: list[str] = list(str(N))  # Convert octal integer to list of digit characters
    def Helper(DigitList: list[str], Base: int) -> int:
        if not DigitList:
            return 0
        LastDigit: int = int(DigitList.pop())  # Get the least significant digit
        return LastDigit * Base + Helper(DigitList, Base * 8)
    return Helper(Digits, 1)

