class PrimeDivisorFinder:
    @staticmethod
    def find_smallest(n: int) -> int:
        # Handle the case where n is 1 (has no prime divisors other than itself)
        if n == 1:
            return 1
        # Check if 2 is the smallest prime divisor
        if n % 2 == 0:
            return 2
        # Iterate over odd numbers up to sqrt(n) to find the smallest divisor without using range or while loops
        limit = int(n**0.5) + 1
        for i in itertools.takewhile(lambda x: x < limit, itertools.count(3, 2)):
            if n % i == 0:
                return i
        return n

