def check_Consecutive(l: list[int]) -> bool:
    if len(l) <= 1:
        return True
    # Exactly 1 while loop to find min and max values
    MinVal: int = l[0]
    MaxVal: int = l[0]
    I: int = 1
    while I < len(l):
        if l[I] < MinVal:
            MinVal = l[I]
        if l[I] > MaxVal:
            MaxVal = l[I]
        I += 1
    # Must use set for O(1) presence checks
    LSet: set[int] = set(l)
    # Exactly 1 list comprehension to check all values in range are present
    AllPresent: list[bool] = [x in LSet for x in range(MinVal, MaxVal + 1)]
    return all(AllPresent) and len(l) == (MaxVal - MinVal + 1)

