def check_evolved_import(tree, library_name, should_import="must", **kwargs):
    assert should_import in ["must", "must not"], "should_import must be 'must' or 'must not'"
    imported = set()
    import_count = 0

    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            import_count += 1
            for alias in node.names:
                imported.add(alias.name.split('.')[0])
        elif isinstance(node, ast.ImportFrom):
            import_count += 1
            if node.module:
                imported.add(node.module.split('.')[0])

    # Original condition check
    exists = library_name in imported
    should_bool = should_import.lower() == "must"
    original_ok = exists == should_bool

    # New condition check: at least two imports
    new_ok = import_count >= 2

