        self.name: str = name
        self.height: int = height

def sortPeople(names: list[str], heights: list[int]) -> list[str]:
    people: list[Person] = [Person(name, height) for name, height in zip(names, heights)]

    def recursive_selection_sort(arr: list[Person], start: int = 0) -> None:
        n: int = len(arr)
        if start >= n - 1:
            return
        max_idx: int = start
        for j in range(start + 1, n):
            if arr[j].height > arr[max_idx].height:
                max_idx = j
        arr[start], arr[max_idx] = arr[max_idx], arr[start]
        recursive_selection_sort(arr, start + 1)

    recursive_selection_sort(people)
    return [person.name for person in people]

