def findMode(root):
    def in_order_generator(node):
        if node:
            yield from in_order_generator(node.left)
            yield node.val
            yield from in_order_generator(node.right)

    prev = None
    mx = cnt = 0
    ans = []
    # Use generator expression to iterate over the in-order values
    for val in (v for v in in_order_generator(root)):
        cnt = cnt + 1 if prev == val else 1
        if cnt > mx:
            ans = [val]
            mx = cnt
        elif cnt == mx:
            ans.append(val)
        prev = val
    return ans

