class ChandrasekharSieve:
    def __init__(self, n: int):
        self.n = n
        self.primes = self.generate_primes()

    def generate_primes(self) -> list[int]:
        if self.n < 2:
            return []

        primes = [2]
        if self.n < 3:
            return primes

        # Sieve for odd numbers: index i corresponds to number (2*i +3)
        sieve_size = (self.n - 1) // 2
        sieve = [True] * sieve_size

        for i in range(sieve_size):
            if sieve[i]:
                current_prime = 2 * i + 3  # Nested variable as required
                # Start marking multiples from current_prime*current_prime (odd), step by current_prime (to keep odd)
                start_idx = (current_prime * current_prime - 3) // 2
                if start_idx >= sieve_size:
                    continue
                for j in range(start_idx, sieve_size, current_prime):
                    sieve[j] = False

        # Collect all unmarked odd primes using list comprehension
        odd_primes = [2 * i + 3 for i in range(sieve_size) if sieve[i]]
        primes.extend(odd_primes)

        return primes

    def get_primes(self) -> list[int]:
        return self.primes

