    import ast
    from seagent.stages.template.check_instruction import ConstraintValidator

    # 1. Parse Response
    code_group = re.search(r"```.*?\n(.*?)```", response, flags = re.DOTALL)
    if code_group:
        response = code_group.group(1)

    # 2. Define Constraints Data
    constraints = [{'function': 'check_data_structure_usage', 'non_checkable': False, 'params': {'data_structure': 'dict', 'must_use': 'must'}}, {'function': 'check_variable_initial_value_in_nested_block', 'non_checkable': False, 'params': {'variable_name': 'current_piece_length', 'initial_value': 'len(piece)'}}, {'function': 'check_inline_construct_count', 'non_checkable': False, 'params': {'construct_type': 'list comprehension', 'count': '1', 'comparison': 'exactly'}}, {'function': 'check_forbidden_builtins', 'non_checkable': False, 'params': {'forbidden_functions': 'all'}}, {'function': 'check_forbidden_loop_type', 'non_checkable': False, 'params': {'loop_type': 'while'}}]
    if not constraints:
        return 1.0

    # 3. Dynamic Function Registration
    custom_funcs = {}
    # === Dynamic Evolved Checkers ===
    import ast

    def add_parent_pointers(tree):
        """Add parent attributes to all AST nodes."""
        for node in ast.walk(tree):
            for child in ast.iter_child_nodes(node):
                child.parent = node
                add_parent_pointers(child)

    def is_inside_nested_block(node):
        """Check if the node is inside a nested block (if/for/while/try/with)."""
        current = node
        while hasattr(current, 'parent'):
            parent = current.parent
            if isinstance(parent, (ast.If, ast.For, ast.While, ast.Try, ast.With)):
                return True
            current = parent
        return False

    def normalize_str(s):
        """Normalize strings by stripping quotes and whitespace."""
        s = str(s).strip()
        if len(s)>=2 and ((s.startswith('"') and s.endswith('"')) or (s.startswith("'") and s.endswith("'"))):
            return s[1:-1]
        return s

    def check_variable_initial_value_in_nested_block(tree, variable_name, initial_value, **kwargs):
        """Check if variable is assigned to initial value inside a nested block."""
        add_parent_pointers(tree)
        target_raw = str(initial_value).strip()
        target_normalized = normalize_str(target_raw)

        for node in ast.walk(tree):
            if isinstance(node, ast.Assign):
                for target in node.targets:
                    if isinstance(target, ast.Name) and target.id == variable_name:
                        # Check initial value (original logic)
                        try:
                            code_val_raw = ast.unparse(node.value).strip()
                        except AttributeError:
                            if isinstance(node.value, ast.Constant):
                                code_val_raw = str(node.value.value)
                            elif isinstance(node.value, ast.Name):
                                code_val_raw = node.value.id
                            else:
                                continue
                        code_val_normalized = normalize_str(code_val_raw)
                        if code_val_raw != target_raw and code_val_normalized != target_normalized:
                            continue
                        # Check nested block constraint
                        if is_inside_nested_block(node):
                            return True
        return False


    custom_funcs['check_variable_initial_value_in_nested_block'] = check_variable_initial_value_in_nested_block


    # 4. Initialize Validator with custom functions
    validator = ConstraintValidator(dynamic_functions=custom_funcs)

    # 5. Execution Loop
    n_total = len(constraints)
    n_succes = 0

    for item in constraints:
        func_name = item.get('function')
        params = item.get('params', {})

        try:
            is_passed = validator.validate(response, func_name, params)          
            if is_passed: n_succes += 1
        except Exception as e:
            # 打印错误方便调试，实际运行时可改为 raise 或记录日志
            # print(f"Check failed for {func_name}: {e}")
            raise e 

    return n_succes / n_total

