def calculateTime(keyboard: str, word: str) -> int:
    POS: dict[str, int] = {}
    I: int = 0
    while I < len(keyboard):
        POS[keyboard[I]] = I
        I += 1

    def helper(CURRENT_POS: int, WORD_IDX: int) -> int:
        if WORD_IDX == len(word):
            return 0
        CHAR: str = word[WORD_IDX]
        NEXT_POS: int = POS[CHAR]
        TIME: int = abs(NEXT_POS - CURRENT_POS)
        return TIME + helper(NEXT_POS, WORD_IDX + 1)

    return helper(0, 0)

