class TreeBalancer:
    @staticmethod
    def is_balanced(root: Optional[Node]) -> bool:
        global is_balanced_flag
        is_balanced_flag = True  # Reset flag for each tree
        processed: List[Tuple[Node, int]] = []
        # Lambda function to get height of a node from processed list (avoids next())
        get_height: Callable[[Optional[Node]], int] = lambda node: (lambda lst: lst[0] if lst else 0)([h for n, h in processed if n == node])
        stack: List[Tuple[Optional[Node], bool]] = [(root, False)]
        while stack and is_balanced_flag:
            node, visited = stack.pop()
            node: Optional[Node]
            visited: bool
            if not visited:
                stack.append((node, True))
                if node.right:
                    stack.append((node.right, False))
                if node.left:
                    stack.append((node.left, False))
            else:
                left_height: int = get_height(node.left)
                right_height: int = get_height(node.right)
                if abs(left_height - right_height) > 1:
                    is_balanced_flag = False
                current_height: int = 1 + max(left_height, right_height)
                processed.append((node, current_height))
        return is_balanced_flag

def is_tree_balanced(root: Optional[Node]) -> bool:
    return TreeBalancer.is_balanced(root)

def check_balanced(root: Optional[Node]) -> bool:
    return TreeBalancer.is_balanced(root)

