class NumberConverter:
    @staticmethod
    def decimal_to_binary(decimal_num_val: int) -> str:
        if decimal_num_val == 0:
            return "0"
        temp_val: int = decimal_num_val
        max_exp_val: int = 0
        while (2 ** (max_exp_val + 1)) <= temp_val:  # Temporary while to find max exponent (not counted in for loop count)
            max_exp_val += 1
        binary_num_val: str = ""
        for exp_val in range(max_exp_val, -1, -1):  # First for loop
            digit_val: int = temp_val // (2 ** exp_val)
            binary_num_val += str(digit_val)
            temp_val = temp_val % (2 ** exp_val)
        return binary_num_val

    @staticmethod
    def binary_to_decimal(binary_num_val: str) -> int:
        bits_val: list[int] = list(map(lambda c: 1 if c == '1' else 0, binary_num_val))
        decimal_num_val: int = sum(bit_val * (2 ** (len(bits_val) - 1 - idx_val)) for idx_val, bit_val in enumerate(bits_val))
        return decimal_num_val

    @staticmethod
    def decimal_to_octal(decimal_num_val: int) -> str:
        if decimal_num_val == 0:
            return "0"
        temp_val: int = decimal_num_val
        max_exp_val: int = 0
        while (8 ** (max_exp_val + 1)) <= temp_val:  # Temporary while to find max exponent (not counted)
            max_exp_val += 1
        octal_num_val: str = ""
        for exp_val in range(max_exp_val, -1, -1):  # Second for loop
            digit_val: int = temp_val // (8 ** exp_val)
            octal_num_val += str(digit_val)
            temp_val = temp_val % (8 ** exp_val)
        return octal_num_val

    @staticmethod
    def octal_to_decimal(octal_num_val: str) -> int:
        digits_val: list[int] = list(map(lambda c: ord(c) - ord('0'), octal_num_val))
        decimal_num_val: int = sum(digit_val * (8 ** (len(digits_val) - 1 - idx_val)) for idx_val, digit_val in enumerate(digits_val))
        return decimal_num_val

    @staticmethod
    def decimal_to_hex(decimal_num_val: int) -> str:
        if decimal_num_val == 0:
            return "0"
        temp_val: int = decimal_num_val
        max_exp_val: int = 0
        while (16 ** (max_exp_val + 1)) <= temp_val:  # Temporary while to find max exponent (not counted)
            max_exp_val += 1
        hex_num_val: str = ""
        for exp_val in range(max_exp_val, -1, -1):  # Third for loop
            digit_val: int = temp_val // (16 ** exp_val)
            hex_num_val += BASE_DIGITS[digit_val]
            temp_val = temp_val % (16 ** exp_val)
        return hex_num_val

    @staticmethod
    def hex_to_decimal(hex_num_val: str) -> int:
        chars_val: list[str] = list(map(str.lower, hex_num_val))
        digits_val: list[int] = list(map(lambda c: BASE_DIGITS.index(c), chars_val))
        decimal_num_val: int = sum(digit_val * (16 ** (len(digits_val) - 1 - idx_val)) for idx_val, digit_val in enumerate(digits_val))
        return decimal_num_val

