from functools import lru_cache
from typing import List, Callable

def longest_increasing_subsequence(arr: List[int]) -> int:
    # Import necessary modules for memoization and type hints
    n: int = len(arr)
    if n == 0:
        return 0

    @lru_cache(maxsize=None)
    def dp(i: int) -> int:
        # Recursive helper to compute LIS ending at index i
        def check_j(j: int) -> int:
            if j >= i:
                return 0
            current: int = dp(j) + 1 if arr[i] > arr[j] else 0
            next_val: int = check_j(j + 1)
            return max(current, next_val)
        # Base case: each element is a subsequence of length 1
        return max(1, check_j(0))

    def find_max(idx: int) -> int:
        # Recursive helper to find maximum LIS across all indices
        if idx == n:
            return 0
        current_dp: int = dp(idx)
        next_max: int = find_max(idx + 1)
        return max(current_dp, next_max)

    # Return the result from the top-level recursive call
    return find_max(0)

