from typing import Optional, Generator

class TreeNode:
    def __init__(self, val: int = 0, left: Optional[TreeNode] = None, right: Optional[TreeNode] = None):
        self.val: int = val
        self.left: Optional[TreeNode] = left
        self.right: Optional[TreeNode] = right

def rangeSumBST(root: Optional[TreeNode], low: int, high: int) -> int:
    # Generator function to yield valid node values using BST properties
    def generate_valid(node: Optional[TreeNode]) -> Generator[int, None, None]:
        # Base case: stop iteration if node is None
        if node is not None:
            if node.val > low:
                yield from generate_valid(node.left)
            if low <= node.val <= high:
                yield node.val
            if node.val < high:
                yield from generate_valid(node.right)
    return sum(generate_valid(root))

