def rangeSumBST(root, low, high):
    def dfs(root):
        if root is None:
            return 0
        x = root.val
        ans = x if low <= x <= high else 0
        if x > low:
            ans += dfs(root.left)
        if x < high:
            ans += dfs(root.right)
        return ans

    return dfs(root)

