from typing import List, Any

class ArrayRotator:
    def __init__(self, arr_var: List[Any]) -> None:
        self.arr_var: List[Any] = arr_var
        self.length_var: int = len(arr_var)

    def rotate(self, split_index_var: int) -> List[Any]:
        # Check if split index is out of valid range (1 to length_var-1)
        if split_index_var >= self.length_var or split_index_var <= 0:
            return self.arr_var[:]
        result_var: List[Any] = []
        count_var: int = 0
        # Use while loop to build result by iterating over split indices
        while count_var < self.length_var:
            index_var: int = (split_index_var + count_var) % self.length_var
            result_var.append(self.arr_var[index_var])
            count_var += 1
        return result_var

def split_Arr(arr_var: List[Any], arr_length_var: int, split_index_var: int) -> List[Any]:  
    rotator_var = ArrayRotator(arr_var)
    return rotator_var.rotate(split_index_var)

