def recur_gcd(gcd_a_val: int, gcd_b_val: int) -> int:
    gcd_remainders_val: list[int] = []
    # Lambda function to compute remainder and update remainders list
    gcd_compute_remainder_val = lambda gcd_high_val, gcd_low_val: (gcd_remainders_val.append(gcd_high_val % gcd_low_val), gcd_remainders_val[-1])[1]
    def gcd_helper(gcd_low_val: int, gcd_high_val: int) -> int:
        gcd_remainder_val: int = gcd_compute_remainder_val(gcd_high_val, gcd_low_val)
        return gcd_low_val if gcd_remainder_val == 0 else gcd_helper(gcd_remainder_val, gcd_low_val)
    gcd_low_val: int = min(abs(gcd_a_val), abs(gcd_b_val))
    gcd_high_val: int = max(abs(gcd_a_val), abs(gcd_b_val))
    return gcd_helper(gcd_low_val, gcd_high_val)

