class MinFinder:
    def find_min(self, list1_val: list[float | int]) -> float | int:
        if not list1_val:
            raise ValueError("List is empty")
        current_min_val = list1_val[0]
        index_val = 1
        # First lambda: get next element
        get_next_val = lambda i_val: list1_val[i_val] if i_val < len(list1_val) else None
        # Second lambda: compare two values
        is_smaller_val = lambda a_val, b_val: a_val < b_val
        while index_val < len(list1_val):
            current_val = get_next_val(index_val)
            if is_smaller_val(current_val, current_min_val):
                current_min_val = current_val
            index_val += 1
        return current_min_val

def largest_neg(list1_val: list[float | int]) -> float | int:
    finder_val = MinFinder()
    return finder_val.find_min(list1_val)

