def count_Divisors(area):
    count_val = 0
    # Binary search to find integer square root without math library
    low_val = 1
    high_val = area
    sqrt_area_val = 0
    while low_val <= high_val:
        mid_val = (low_val + high_val) // 2
        mid_sq_val = mid_val * mid_val
        if mid_sq_val == area:
            sqrt_area_val = mid_val
            break
        elif mid_sq_val < area:
            sqrt_area_val = mid_val
            low_val = mid_val + 1
        else:
            high_val = mid_val - 1
    # Count divisors
    for i_val in range(1, sqrt_area_val + 1):
        if area % i_val == 0:
            if area // i_val == i_val:
                count_val += 1
            else:
                count_val += 2
    return "Even" if count_val % 2 == 0 else "Odd"

