def mySqrt(x):
    def binary_search(l, r):
        if l >= r:
            return l
        mid = (l + r + 1) >> 1
        # Use lambda to encapsulate recursive call selection
        get_next = lambda: binary_search(mid, r) if mid <= x // mid else binary_search(l, mid - 1)
