def dealnnoy_num(n: int, m: int) -> int:
    # Handle base cases directly to meet if statement requirement
    if n == 0 or m == 0:
        return 1
    # Initialize DP table with base cases
    dp: list[list[int]] = [[1] * (m + 1) for _ in range(n + 1)]
    # Fill DP table using nested for loops
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            dp[i][j] = dp[i-1][j] + dp[i][j-1] + dp[i-1][j-1]
    return dp[n][m]

