def islandPerimeter(grid):
    m, n = len(grid), len(grid[0]) if grid else 0
    perimeter = 0
    is_valid_land = lambda x, y: 0 <= x < m and 0 <= y < n and grid[x][y] == 1
    for i in range(m):
        for j in range(n):
            if grid[i][j] == 1:
                adjacent = set()
                for dx, dy in [(-1,0), (1,0), (0,-1), (0,1)]:
                    x, y = i + dx, j + dy
                    if is_valid_land(x, y):
                        adjacent.add((x, y))
                perimeter += 4 - len(adjacent)
    return perimeter

