import heapq as hq
def heap_queue_smallest(NUMS, N):
    if N == 0:
        return []
    # Use a max-heap by inverting values
    MAX_HEAP = []
    for NUM in NUMS:
        if len(MAX_HEAP) < N:
            hq.heappush(MAX_HEAP, -NUM)
        else:
            if NUM < -MAX_HEAP[0]:
                hq.heappop(MAX_HEAP)
                hq.heappush(MAX_HEAP, -NUM)
    # Convert back to positive and sort (to match nsmallest order)
    SMALLEST_NUMS = sorted(-NUM for NUM in MAX_HEAP)
    return SMALLEST_NUMS

