def binary_to_decimal(b_val: int) -> int:
    # Base case: binary 0 converts to decimal 0
    if b_val == 0:
        return 0
    else:
        # Match last digit to compute contribution plus recursive result
        match b_val % 10:
            case 0:
                return 0 + 2 * binary_to_decimal(b_val // 10)
            case 1:
                return 1 + 2 * binary_to_decimal(b_val // 10)
            case _:
                # Raise error for non-binary digits
                raise ValueError("Invalid binary digit")

