def isPalindrome(s):
    # Use list comprehension to clean the string without isalnum: keep letters/numbers, convert to lowercase
    pal_cleaned_chars = [char.lower() for char in s if (char >= 'a' and char <= 'z') or (char >= 'A' and char <= 'Z') or (char >= '0' and char <= '9')]

    def helper(pal_left_idx, pal_right_idx):
        if pal_left_idx >= pal_right_idx:
            return True
        if pal_cleaned_chars[pal_left_idx] != pal_cleaned_chars[pal_right_idx]:
            return False
        return helper(pal_left_idx + 1, pal_right_idx - 1)

    return helper(0, len(pal_cleaned_chars) - 1)

