class CharCounter:
    # 初始化方法，接收输入字符串和目标字符
    def __init__(self, STR_INPUT: str, STR_TARGET: str) -> None:
        self.STR_INPUT = STR_INPUT
        self.STR_TARGET = STR_TARGET

    # 计算指定字符在输入字符串中的出现次数（仅接收self参数）
    def count_char(self) -> int:
        # 使用lambda函数包装count方法统计字符出现次数
        return (lambda s, c: s.count(c))(self.STR_INPUT, self.STR_TARGET)

# 辅助函数，创建CharCounter实例并调用count_char方法
def count(s: str, c: str) -> int:
    return CharCounter(s, c).count_char()

