class ZigzagMemoizer:
    def __init__(self):
        self.memo_var = {}

    def compute(self, n_var, k_var):
        key_var = (n_var, k_var)
        value_var = self.memo_var.get(key_var)
        if value_var is not None:
            return value_var
        value_var = 1 if (n_var == 0 and k_var == 0) else (0 if k_var == 0 else (self.compute(n_var, k_var - 1) + self.compute(n_var - 1, n_var - k_var)))
        self.memo_var[key_var] = value_var
        return value_var

def zigzag(n_var, k_var):
    memoizer_var = ZigzagMemoizer()
    return memoizer_var.compute(n_var, k_var)

