def add_dict(D1: dict[str, int], D2: dict[str, int]) -> dict[str, int]:
    # Combine two dictionaries using while loop and if-else
    KEYS: list[str] = list(set(list(D1.keys()) + list(D2.keys())))
    RES: dict[str, int] = {}
    I: int = 0
    while I < len(KEYS):
        K: str = KEYS[I]
        if K in D1 and K in D2:
            VAL: int = D1[K] + D2[K]
        else:
            VAL: int = sum([D1.get(K, 0), D2.get(K, 0)])
        RES[K] = VAL
        I += 1
