# Class to handle division with precise rounding
class DivisorCalculator:
    @staticmethod
    def calculate(N: int, Sum: int) -> float:
        # Handle division by zero edge case
        if N == 0:
            return 0.00
        else:
            # Use list comprehension with map to create Decimal values list (utilizes map, exactly 1 list comprehension)
            calc1DecimalValues: list[decimal.Decimal] = [x for x in map(decimal.Decimal, [Sum, N])]
            calc2Result: decimal.Decimal = calc1DecimalValues[0] / calc1DecimalValues[1]
            calc3RoundedResult: decimal.Decimal = calc2Result.quantize(decimal.Decimal('0.00'), rounding=decimal.ROUND_HALF_UP)
            return float(calc3RoundedResult)

def Sum_of_Inverse_Divisors(N: int, Sum: int) -> float:
    return DivisorCalculator.calculate(N, Sum)

