def areOccurrencesEqual(s: str) -> bool:
    char_counts: dict[str, int] = {}
    # Exactly one for loop to count character frequencies (no if-else used)
    for char in s:
        char_counts[char] = char_counts.setdefault(char, 0) + 1
    unique_chars: list[str] = [char for char in char_counts.keys()]
    # Use map to get frequency counts from unique characters
    freq_list: list[int] = list(map(lambda c: char_counts[c], unique_chars))
