from typing import List, Dict

def countQuadruplets(nums: List[int]) -> int:
    ans: int = 0
    n: int = len(nums)
    # Use dict to store count of nums[d] for d > c
    count_dict: Dict[int, int] = {}
    # Iterate c from n-2 down to 2 (since a < b < c < d, c must be at least 2, d at least c+1)
    for c in range(n-2, 1, -1):
        # Add nums[c+1] to the dict (d starts from c+1)
        if nums[c+1] in count_dict:
            count_dict[nums[c+1]] += 1
        else:
            count_dict[nums[c+1]] = 1
        # Iterate a from 0 to c-2
        for a in range(c-1):
            # Iterate b from a+1 to c-1
            for b in range(a+1, c):
                target: int = nums[a] + nums[b] + nums[c]
                if target in count_dict:
                    ans += count_dict[target]
    return ans

