def findTheLongestBalancedSubstring(s: str) -> int:
    def helper(index_var: int, counts_var: dict[str, int], max_len_var: int) -> int:
        if index_var == len(s):
            return max_len_var
        char_var = s[index_var]
        match char_var:
            case '0':
                if counts_var['1'] > 0:
                    new_counts_var = {'0': 1, '1': 0}
                else:
                    new_counts_var = {'0': counts_var['0'] + 1, '1': counts_var['1']}
                new_max_len_var = max_len_var
            case '1':
                new_counts_var = {'0': counts_var['0'], '1': counts_var['1'] + 1}
                if new_counts_var['1'] <= new_counts_var['0']:
                    current_len_var = 2 * new_counts_var['1']
                    new_max_len_var = max(max_len_var, current_len_var)
                else:
                    new_max_len_var = max_len_var
                return helper(index_var + 1, new_counts_var, new_max_len_var)
        return helper(index_var + 1, new_counts_var, new_max_len_var)
    return helper(0, {'0': 0, '1': 0}, 0)

