def findTheLongestBalancedSubstring(s):
    def check(i, j):
        cnt = 0
        for k in range(i, j + 1):
            if s[k] == '1':
                cnt += 1
            elif cnt:
                return False
        return cnt * 2 == (j - i + 1)

    n = len(s)
    ans = 0
    for i in range(n):
        for j in range(i + 1, n):
            if check(i, j):
                ans = max(ans, j - i + 1)
    return ans

