        ones_count: int = self.binary_string.count('1')
        total_length: int = len(self.binary_string)

        zeroes_percentage: float = (zeroes_count / total_length) if total_length != 0 else 0.0
        ones_percentage: float = (ones_count / total_length) if total_length != 0 else 0.0

        return {
            'Zeroes': zeroes_percentage,
            'Ones': ones_percentage,
            'Bit length': total_length
        }

    def convert_to_ascii(self) -> str:
        bytes_list: List[int] = [int(self.binary_string[i:i+8], 2) for i in range(0, len(self.binary_string), 8)]
