def is_subset_sum(input_set, num_elements, target_sum):
    # Initialize dict to track achievable sums (base case: sum 0 is achievable)
    achievable_sums = {0: True}
    # First for loop: iterate over each element in the input set
    for element in input_set[:num_elements]:
        # Second for loop: iterate over current achievable sums (copy to avoid modification during iteration)
        current_sums = list(achievable_sums.keys())
        for current_sum in current_sums:
            new_sum = current_sum + element
            if new_sum not in achievable_sums:
                achievable_sums[new_sum] = True
    # Check if target_sum is in the achievable sums dict
    return target_sum in achievable_sums

