def check_abundant(n):
    divisors = set()
    i = 1
    while i * i <= n:
        if n % i == 0:
            divisors.add(i)
            if i != n // i:
                divisors.add(n // i)
        i += 1
    proper_sum = sum([d for d in divisors if d != n])
    return proper_sum > n

