def common_prefix(arr, n):
    if n == 0:
        return ""
    # Find the minimum length to limit the number of positions to check
    min_len = min(len(s) for s in arr)
    prefix = []
    for i in range(min_len):
        # Use a dict to count occurrences of each character at position i
        char_count = {}
        for s in arr:
            char = s[i]
            char_count[char] = char_count.get(char, 0) + 1
        # If all strings have the same character at this position
        if char_count[arr[0][i]] == n:
            prefix.append(arr[0][i])
        else:
            break
    return ''.join(prefix)

