from typing import List

class NLPDataProcessor:
    def construct_stop_word_list(self) -> List[str]:
        return ['a', 'an', 'the']

    def remove_stop_words(self, string_list: List[str], stop_word_list: List[str]) -> List[List[str]]:
        result = []
        for s in string_list:
            words = s.split()
            filtered_words = [word for word in words if word not in stop_word_list]
            result.append(filtered_words)
        return result

    def process(self, string_list: List[str]) -> List[List[str]]:
        stop_words = self.construct_stop_word_list()
        return self.remove_stop_words(string_list, stop_words)

def daysBetweenDates(date1, date2):
    def isLeapYear(year):
        return year % 4 == 0 and (year % 100 != 0 or year % 400 == 0)

    def daysInMonth(year, month):
        days = [
            31,
            28 + int(isLeapYear(year)),
            31,
            30,
            31,
            30,
            31,
            31,
            30,
            31,
            30,
            31,
        ]
        return days[month - 1]

    def calcDays(date):
        year, month, day = map(int, date.split("-"))
        days = 0
        for y in range(1971, year):
            days += 365 + int(isLeapYear(y))
        for m in range(1, month):
            days += daysInMonth(year, m)
        days += day
        return days

    return abs(calcDays(date1) - calcDays(date2))

