    def recursive_search(bsStart: int, bsEnd: int) -> bool:
        if bsStart > bsEnd:
            return False
        bsMid: int = (bsStart + bsEnd) // 2
        if bsItemList[bsMid] == bsItem:
            return True
        return recursive_search(bsStart, bsMid - 1) if bsItem < bsItemList[bsMid] else recursive_search(bsMid + 1, bsEnd)
    if not isinstance(bsItemList, list):
