factor_cache = {}

def amicable_numbers_sum(limit):
    global factor_cache
    factor_cache.clear()  # Clear cache for each function call to avoid state persistence
    if not isinstance(limit, int):
        return "Input is not an integer!"
    if limit < 1:
        return "Input must be bigger than 0!"
    amicables = set()
    for num in range(2, limit + 1):
        if num in amicables:
            continue
        # Calculate sum of factors using cache
        if num not in factor_cache:
            factor_cache[num] = sum([fact for fact in range(1, num) if num % fact == 0])
