        if sum_fact not in factor_cache:
            factor_cache[sum_fact] = sum([fact for fact in range(1, sum_fact) if sum_fact % fact == 0])
        sum_fact2 = factor_cache[sum_fact]
        if num == sum_fact2 and num != sum_fact:
            amicables.add(num)
            amicables.add(sum_fact)
    return sum(amicables)

