def max_chain_length(arr, n): 
    if n == 0:
        return 0
    # Custom bubble sort to sort events by end time (using lambda for comparison)
    arr_copy = arr.copy()
    compare = lambda x, y: x.b > y.b
    for i in range(n):
        for j in range(0, n - i - 1):
            if compare(arr_copy[j], arr_copy[j + 1]):
                arr_copy[j], arr_copy[j + 1] = arr_copy[j + 1], arr_copy[j]
    count = 1
    last_end = arr_copy[0].b
    for event in arr_copy[1:]:
        if event.a > last_end:
            count += 1
            last_end = event.b
    return count

