def heap_queue_largest(nums, n):
    # Initialize an empty min-heap
    heap = []
    index = 0
    # Replace for loop with while loop (1st while loop)
    while index < len(nums):
        num = nums[index]
        if len(heap) < n:
            # Add to heap if not full
            heap.append(num)
            # Maintain heap property (bubble up - 2nd while loop)
            i = len(heap) - 1
            while i > 0 and heap[i] < heap[(i - 1) // 2]:
                heap[i], heap[(i - 1) // 2] = heap[(i - 1) // 2], heap[i]
                i = (i - 1) // 2
        else:
            # If current num is larger than heap's smallest element (root)
            if num > heap[0]:
                # Replace root with current num
                heap[0] = num
                # Maintain heap property (bubble down - 3rd while loop)
                i = 0
                while 2 * i + 1 < len(heap):
                    min_child = 2 * i + 1
                    if 2 * i + 2 < len(heap) and heap[2 * i + 2] < heap[min_child]:
                        min_child = 2 * i + 2
                    if heap[i] <= heap[min_child]:
                        break
                    heap[i], heap[min_child] = heap[min_child], heap[i]
                    i = min_child
        index += 1
    # Return sorted heap to match original output order (nlargest returns sorted list)
    return sorted(heap, reverse=True)

