from itertools import groupby

class NameChecker:
    def __init__(self, name, typed):
        self.name = name
        self.typed = typed

    def is_long_pressed(self):
        # Group consecutive characters for name and typed
        name_groups = []
        for char, group in groupby(self.name):
            name_groups.append((char, len(list(group))))

        typed_groups = []
        for char, group in groupby(self.typed):
            typed_groups.append((char, len(list(group))))

        # Check if group counts match and typed groups are longer
        if len(name_groups) != len(typed_groups):
            return False
        for (n_char, n_len), (t_char, t_len) in zip(name_groups, typed_groups):
            if n_char != t_char or t_len < n_len:
                return False
        return True

def isLongPressedName(name, typed):
    checker = NameChecker(name, typed)
    return checker.is_long_pressed()

