def re_arrange(arr, n):
    negatives = [num for num in arr if num < 0]
    non_negatives = [num for num in arr if num >= 0]
    result = []

    def interleave(i):
        if i < len(negatives):
            result.append(negatives[i])
        if i < len(non_negatives):
            result.append(non_negatives[i])
        if i + 1 < len(negatives) or i + 1 < len(non_negatives):
            interleave(i + 1)

    interleave(0)
    return [result[i] for i in range(n)] if len(result) >= n else result

