from datetime import datetime
import numpy as np
from typing import List, Tuple

class MovieBookingSystem:
    def __init__(self) -> None:
        self.movies = []

    def add_movie(self, name: str, price: float, start_time: str, end_time: str, n: int) -> None:
        movie = {
            'name': name,
            'price': price,
            'start_time': datetime.strptime(start_time, '%H:%M'),
            'end_time': datetime.strptime(end_time, '%H:%M'),
            'seats': np.zeros((n, n), dtype=int)  # Use int for clarity (0/1)
        }
        self.movies.append(movie)

    def book_ticket(self, name: str, seats_to_book: List[Tuple[int, int]]) -> str:
        # Find movie (case-sensitive)
        movie = next((m for m in self.movies if m['name'] == name), None)
        if not movie:
            return "Movie not found."

        n = movie['seats'].shape[0]

        # Validate all seats first
        for row, col in seats_to_book:
            # Check bounds
            if row <0 or row >=n or col <0 or col >=n:
                return "Booking failed."
            # Check availability
            if movie['seats'][row][col] !=0:
                return "Booking failed."

        # Book all seats if valid
        for row, col in seats_to_book:
            movie['seats'][row][col] = 1

        return "Booking success."

    def available_movies(self, start_time: str, end_time: str) -> List[str]:
        user_start = datetime.strptime(start_time, '%H:%M')
        user_end = datetime.strptime(end_time, '%H:%M')

        available = []
        for movie in self.movies:
            if user_start <= movie['start_time'] and movie['end_time'] <= user_end:
                available.append(movie['name'])

        return available

