    def __init__(self, db_name: str) -> None:
        self.connection = sqlite3.connect(db_name)
        self.cursor = self.connection.cursor()

    def create_table(self) -> None:
        create_query = """
            CREATE TABLE IF NOT EXISTS users (
                username TEXT,
                password TEXT
            )
        """
        self.cursor.execute(create_query)
        self.connection.commit()

    def insert_user(self, username: str, password: str) -> None:
        insert_query = "INSERT INTO users (username, password) VALUES (?, ?)"
        self.cursor.execute(insert_query, (username, password))
        self.connection.commit()

    def search_user_by_username(self, username: str) -> Optional[Tuple[str, str]]:
        search_query = "SELECT username, password FROM users WHERE username = ?"
        self.cursor.execute(search_query, (username,))
        return self.cursor.fetchone()

    def delete_user_by_username(self, username: str) -> None:
        delete_query = "DELETE FROM users WHERE username = ?"
        self.cursor.execute(delete_query, (username,))
        self.connection.commit()

    def validate_user_login(self, username: str, password: str) -> bool:
        user = self.search_user_by_username(username)
        return user is not None and user[1] == password

