def sequential_search(dlist, item):
    pos = 0
    found = False
    while pos < len(dlist) and not found:
        if dlist[pos] == item:
            found = True
        else:
            pos = pos + 1
    return found, pos

class HRManagementSystem:
    def __init__(self):
        self.employees = {}

    def add_employee(self, employee_id: int, name: str, position: str, department: str, salary: int) -> bool:
        if employee_id in self.employees:
            return False
        self.employees[employee_id] = {
            'name': name,
            'position': position,
            'department': department,
            'salary': salary
        }
        return True

    def remove_employee(self, employee_id: int) -> bool:
        if employee_id in self.employees:
            del self.employees[employee_id]
            return True
        return False

    def update_employee(self, employee_id: int, employee_info: dict) -> bool:
        employee = self.get_employee(employee_id)
        if not employee:
            return False
        # Check for invalid keys
        for key in employee_info:
            if key not in employee:
                return False
        # Apply valid updates
        employee.update(employee_info)
        return True

    def get_employee(self, employee_id: int) -> dict | bool:
        return self.employees.get(employee_id, False)

    def list_employees(self) -> dict:
        employee_data = {}
        for emp_id, emp_info in self.employees.items():
            employee_data[emp_id] = {'employee_ID': emp_id, **emp_info}
        return employee_data

