class DigitValidator:
    def validate(self, dv_n: int, dv_base: int) -> bool:
        dv_s: str = str(dv_n)
        # 使用列表推导式计算每个数字的频率，不使用Counter或str.count
        dv_frequencies: list[int] = [len([dv_c for dv_c in dv_s if dv_c == str(dv_digit)]) for dv_digit in range(dv_base)]
        dv_pairs: list[tuple[int, int]] = list(zip(dv_frequencies, range(dv_base)))
        return self._check_conditions(dv_pairs)

    def _check_conditions(self, dv_pairs: list[tuple[int, int]]) -> bool:
        # 递归检查每个频率-数字对的有效性
        if not dv_pairs:
            return True
        else:
            dv_freq, dv_digit = dv_pairs[0]
            if dv_freq > dv_digit:
                return False
            else:
                return self._check_conditions(dv_pairs[1:])

def validate(dv_n: int, dv_base: int = 10) -> bool:
    # 创建DigitValidator实例并调用validate方法
    dv_validator: DigitValidator = DigitValidator()
    return dv_validator.validate(dv_n, dv_base)

