from typing import List

def merge(a: List[int], b: List[int]) -> List[int]:
    result: List[int] = []
    i: int = 0
    j: int = 0
    while i < len(a) and j < len(b):
        if a[i] < b[j]:
            result.append(a[i])
            i += 1
        else:
            result.append(b[j])
            j += 1
    result.extend(a[i:])
    result.extend(b[j:])
    return result

def merge_sort(x: List[int]) -> List[int]:
    if len(x) <= 1:
        return x
    middle: int = len(x) // 2
    left: List[int] = merge_sort(x[:middle])
    right: List[int] = merge_sort(x[middle:])
    return reduce(merge, [left, right])

