    def __init__(self, a, n, r):
        self.a = a
        self.n = n
        self.r = r

    def calculate_sum(self):
        match self.r:
            case 1:
                return self.a * self.n
            case _:
                return (self.a * (1 - pow(self.r, self.n))) / (1 - self.r)

