def finalString(s: str) -> str:
    def helper(my_index_var: int, my_current_list_var: list[str]) -> str:
        if my_index_var == len(s):
            return "".join(my_current_list_var)
        my_char_var: str = s[my_index_var]
        if my_char_var == "i":
            # Use list comprehension to reverse the list
            my_new_list_var: list[str] = [my_current_list_var[i] for i in range(len(my_current_list_var)-1, -1, -1)]
        else:
            my_new_list_var: list[str] = my_current_list_var + [my_char_var]
        return helper(my_index_var + 1, my_new_list_var)
    return helper(0, [])

