T = TypeVar('T')

class TupleAppender:
    @staticmethod
    def append_list(test_list: List[T], test_tup: Tuple[T, ...]) -> Tuple[T, ...]:
        # 初始化结果元组为输入元组
        RES_TUP: Tuple[T, ...] = test_tup
        # 获取元组元素的类型（如果元组非空）
        TUPLE_TYPE = type(test_tup[0]) if test_tup else None
        # 遍历列表中的每个元素
        for ELEM in test_list:
            # 检查元素类型是否与元组元素类型匹配
            if isinstance(ELEM, TUPLE_TYPE) if TUPLE_TYPE else True:
                # 将元素作为单元素元组与结果元组拼接
                RES_TUP += (ELEM,)
            else:
                # 类型不匹配时输出错误信息并抛出异常
                ERROR_MSG = "Element type mismatch with tuple elements"
                sys.stderr.write(ERROR_MSG + "\n")
                raise TypeError(ERROR_MSG)
        # 返回最终的结果元组
        return RES_TUP

def add_lists(test_list: List[T], test_tup: Tuple[T, ...]) -> Tuple[T, ...]:
