def is_valid_parenthese(str1):
    get_closing = lambda c: ')' if c == '(' else '}' if c == '{' else ']' if c == '[' else None

    class StackSimulator:
        def __init__(self):
            self.stack = {}
            self.top = -1

        def push(self, char):
            self.top += 1
            self.stack[self.top] = char

        def pop(self):
            if self.top == -1:
                return None
            char = self.stack[self.top]
            del self.stack[self.top]
            self.top -= 1
            return char

        def is_empty(self):
            return self.top == -1

        def get_top(self):
            if self.top == -1:
                return None
            return self.stack[self.top]

    def validate_char(char, stack_sim):
        match char:
            case '(' | '{' | '[':
                stack_sim.push(char)
                return True
            case ')' | '}' | ']':
                if stack_sim.is_empty():
                    return False
                opening_char = stack_sim.get_top()
                stack_sim.pop()
                expected = get_closing(opening_char)
                if char != expected:
                    return False
                return True
            case _:
                return True

    def recursive_check(index, stack_sim):
        if index == len(str1):
            return stack_sim.is_empty()
        char = str1[index]
        valid = validate_char(char, stack_sim)
        if not valid:
            return False
        return recursive_check(index + 1, stack_sim)

    stack = StackSimulator()
    return recursive_check(0, stack)

