class DivisorSumChecker:
    @staticmethod
    def calculate_div_sum(n: int) -> int:
        match n:
            case 1:
                return 0
            case _:
                # Exactly one list comprehension to generate divisor pairs
                divisor_pairs: list[tuple[int, int]] = [(i, n//i) for i in range(2, n) if i*i <= n and n%i == 0]
                # Use itertools.chain to flatten pairs into a single iterable for the set
                divisors: set[int] = set(itertools.chain([1], *divisor_pairs))
                return sum(divisors)

    @staticmethod
    def are_equivalent(num1: int, num2: int) -> bool:
        return DivisorSumChecker.calculate_div_sum(num1) == DivisorSumChecker.calculate_div_sum(num2)

def areEquivalent(num1: int, num2: int) -> bool:
