class Trapezium:
    def __init__(self, base1: float, base2: float, height: float) -> None:
        # Validate that all dimensions are non-negative
        if base1 >= 0 and base2 >= 0 and height >= 0:
            self.base1: float = base1
            self.base2: float = base2
            self.height: float = height
        else:
            raise ValueError("Bases and height must be non-negative values.")

    def area(self) -> float:
        # Calculate area using the trapezium formula
        area_val: float = 0.5 * (self.base1 + self.base2) * self.height
        return area_val

