class TreeBalancer:
    @staticmethod
    def is_balanced(root):
        global is_balanced_flag
        is_balanced_flag = True  # Reset flag for each tree
        processed = []
        # Lambda function to get height of a node from processed list (avoids next())
        get_height = lambda node: (lambda lst: lst[0] if lst else 0)([h for n, h in processed if n == node])
        stack = [(root, False)]
        while stack and is_balanced_flag:
            node, visited = stack.pop()
            if not visited:
                stack.append((node, True))
                # Combine node.right and node.left checks into a single list comprehension (removes 2 ifs)
                stack.extend([(child, False) for child in [node.right, node.left] if child])
            else:
                left_height = get_height(node.left)
                right_height = get_height(node.right)
                if abs(left_height - right_height) > 1:
                    is_balanced_flag = False
                current_height = 1 + max(left_height, right_height)
                processed.append((node, current_height))
        return is_balanced_flag

def is_tree_balanced(root):
    return TreeBalancer.is_balanced(root)

def check_balanced(root):
    return TreeBalancer.is_balanced(root)

