from contextlib import closing


class StudentDatabaseProcessor:

    def __init__(self, database_name):
        self.database_name = database_name

    def create_student_table(self):
        with closing(sqlite3.connect(self.database_name)) as conn:
            conn.cursor().execute("""
            CREATE TABLE IF NOT EXISTS students (
                id INTEGER PRIMARY KEY,
                name TEXT,
                age INTEGER,
                gender TEXT,
                grade INTEGER
            )
            """)
            conn.commit()

    def insert_student(self, student_data):
        if all(key in student_data for key in ['name', 'age', 'gender', 'grade']):
            # Validate data types using match/case
            for key, value in student_data.items():
                match key:
                    case 'name' | 'gender':
                        if not isinstance(value, str):
                            raise TypeError(f"{key} must be a string")
                    case 'age' | 'grade':
                        if not isinstance(value, int):
                            raise TypeError(f"{key} must be an integer")
                        if value <= 0:
                            raise ValueError(f"{key} must be a positive integer")
            with closing(sqlite3.connect(self.database_name)) as conn:
                conn.cursor().execute("""
                INSERT INTO students (name, age, gender, grade)
                VALUES (?, ?, ?, ?)
                """, (student_data['name'], student_data['age'], student_data['gender'], student_data['grade']))
                conn.commit()
        else:
            raise ValueError("student_data missing required keys: name, age, gender, grade")

    def search_student_by_name(self, name):
        with closing(sqlite3.connect(self.database_name)) as conn:
            return conn.cursor().execute("SELECT * FROM students WHERE name = ?", (name,)).fetchall()

    def delete_student_by_name(self, name):
        with closing(sqlite3.connect(self.database_name)) as conn:
            conn.cursor().execute("DELETE FROM students WHERE name = ?", (name,))
            conn.commit()

