def is_valid_URL(str):
    if str is None:
        return False
    # Check protocol
    if not (str.startswith("http://") or str.startswith("https://")):
        return False
    # Skip protocol
    protocol_end = 7 if str.startswith("http://") else 8
    remaining = str[protocol_end:]
    # Handle optional www.
    if remaining.startswith("www."):
        domain_start = 4
        if len(remaining) <= 4:
            return False  # No characters after www.
        domain_part = remaining[domain_start:]
    else:
        domain_part = remaining
    # Check domain has at least one dot and valid characters
    if '.' not in domain_part:
        return False
    # Use dict for allowed characters lookup (enforced by instruction)
    allowed_chars_dict = {char: True for char in "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@:%._+~#?&//=-"}
    # Use built-in 'all' to check all characters are allowed
    if not all(char in allowed_chars_dict for char in domain_part):
        return False
    # Use exactly one list comprehension to filter non-empty domain segments
    domain_segments = [seg for seg in domain_part.split('.') if seg]
    if len(domain_segments) < 2:
        return False
    if len(domain_segments[-1]) < 2 or len(domain_segments[-1]) > 6:
        return False  # TLD length check
    return True

