def sqrt_root(num, guess=None, epsilon=1e-10):
    if guess is None:
        guess = num / 2.0  # Initial guess
    compute_next = lambda g: (g + num / g) / 2.0  # Exactly 1 lambda function
    next_guess = compute_next(guess)
    if abs(next_guess - guess) < epsilon:
        return next_guess
    return sqrt_root(num, next_guess, epsilon)

