def rangeSumBST(root: Optional[TreeNode], low: int, high: int) -> int:
    # Recursive generator to yield valid product prices using inventory tree properties
    def dfs(node: Optional[TreeNode]) -> Generator[int, None, None]:
        # Base case: yield nothing if node is None
        if node is not None:
            if low <= node.val <= high:
                yield node.val
            if node.val > low:
                yield from dfs(node.left)
            if node.val < high:
                yield from dfs(node.right)
    return sum(v for v in dfs(root))

