class StringSplitter:
    @staticmethod
    def split(text):
        substrings = []
        start = None
        for idx, char in enumerate(text):
            if char.islower():
                if start is not None:
                    substrings.append(text[start:idx])
                start = idx
            elif start is None:
                continue
        if start is not None:
            substrings.append(text[start:])
        return substrings

def split_lowerstring(text):
    return StringSplitter.split(text)

